mapper.select:
SELECT  FROM wo_work_order
 WHERE tenant_id=#{tenantId}

  AND project_id IN CAST(#{id} AS uuid)
AND FALSE
AND client_code=#{clientCode}
AND project_id=#{projectId}
AND status=#{status}
AND (received_at,id) < (#{cursorReceivedAt},#{cursorId})
ORDER BY received_at DESC,id DESC LIMIT #{fetchSize}
